// ═══════════════════════════════════════════════════════════════════
// SVG FLOW PARTICLES - Synthograsizer Workflow Template
// Full p5.js port of SVG flow field particle system
// ═══════════════════════════════════════════════════════════════════

const CW = 500;
const PI = Math.PI;
const TWO_PI = PI * 2;

// ─── PALETTES ─────────────────────────────────────────────────────
const PALETTES = {
  'warm sunset':  ['#ff8a9b','#6b5b95','#88d8c0','#ffd23f','#f7f3e9'],
  'cool ocean':   ['#3498db','#5dade2','#1abc9c','#2c3e50','#ecf0f1'],
  'earth tones':  ['#8b4513','#228b22','#cd853f','#b22222','#2e8b57'],
  'neon vivid':   ['#ff6b6b','#4ecdc4','#45b7d1','#96ceb4','#dda0dd'],
  'pastels':      ['#f7cac9','#f7786b','#92a8d1','#034f84','#dda0dd'],
  'monochrome':   ['#2c3e50','#34495e','#7f8c8d','#95a5a6','#ecf0f1']
};

// ─── PARAMETER MAPS ───────────────────────────────────────────────
const densityMap = { sparse:20, light:40, moderate:80, dense:150, swarm:250, overwhelming:400 };
const energyMap = {
  still:    { chaos:0.3, speed:0.02 },
  gentle:   { chaos:0.8, speed:0.05 },
  moderate: { chaos:2.0, speed:0.10 },
  energetic:{ chaos:3.0, speed:0.15 },
  turbulent:{ chaos:4.0, speed:0.18 },
  chaotic:  { chaos:5.0, speed:0.22 }
};
const trailLenMap = { dots:3, short:10, medium:20, flowing:40, ribbons:60, streams:100 };
const trailOpMap = { faint:0.15, subtle:0.25, medium:0.4, visible:0.55, bright:0.75, vivid:0.9 };
const noiseMap = { smooth:0.001, rolling:0.004, organic:0.012, complex:0.035, turbulent:0.08, fractured:0.18 };
const colorShiftMap = { none:0, subtle:8, moderate:18, dramatic:35 };
const waveMap = {
  none:    { count:0, height:0 },
  subtle:  { count:4, height:0.04 },
  gentle:  { count:6, height:0.08 },
  rhythmic:{ count:10, height:0.12 },
  bold:    { count:14, height:0.2 },
  intense: { count:20, height:0.3 }
};
const grainMap = { none:0, whisper:0.03, light:0.06, medium:0.1, heavy:0.18, gritty:0.3 };
const symMap = { none:0, bilateral:2, quadrilateral:4, radial:6, kaleidoscope:8, snowflake:12 };
const frameMap = {
  none:    { width:0, matting:false },
  thin:    { width:0.01, matting:false },
  classic: { width:0.02, matting:false },
  matted:  { width:0.015, matting:true },
  ornate:  { width:0.025, matting:true },
  gallery: { width:0.03, matting:true }
};
const distMap = { none:0, subtle:8, gentle:25, warped:50, melting:80, liquid:120 };

// ─── STATE ────────────────────────────────────────────────────────
let particles = [];
let waves = [];
let bgParticles = [];
let breathCircles = [];
let time = 0;
let palette = [];
let prevDensity = -1;
let prevPaletteName = '';
let prevWaveCount = -1;
let noiseOff = 0;

// ─── SETUP ────────────────────────────────────────────────────────
p.setup = function() {
  p.createCanvas(CW, CW);
  p.colorMode(p.HSB, 360, 100, 100, 100);
  noiseOff = p.random(10000);
  p.print('Flow Particles ready');
};

// ─── HELPERS ──────────────────────────────────────────────────────
function hexToHSB(hex) {
  let r = parseInt(hex.slice(1,3),16)/255;
  let g = parseInt(hex.slice(3,5),16)/255;
  let b = parseInt(hex.slice(5,7),16)/255;
  let mx = Math.max(r,g,b), mn = Math.min(r,g,b);
  let d = mx - mn, h = 0, s = mx ? d/mx*100 : 0, br = mx*100;
  if (d) {
    if (mx===r) h = ((g-b)/d + (g<b?6:0)) * 60;
    else if (mx===g) h = ((b-r)/d + 2) * 60;
    else h = ((r-g)/d + 4) * 60;
  }
  return [h, s, br];
}

function getColor(idx, pal, shift) {
  let hex = pal[idx % pal.length];
  let [h, s, br] = hexToHSB(hex);
  if (shift > 0) {
    let seed = idx * 73.7;
    h = (h + (p.noise(seed) - 0.5) * 2 * shift + 360) % 360;
    s = p.constrain(s + (p.noise(seed + 100) - 0.5) * 2 * shift * 0.5, 10, 100);
    br = p.constrain(br + (p.noise(seed + 200) - 0.5) * 2 * shift * 0.3, 15, 95);
  }
  return p.color(h, s, br);
}

function initParticles(count, bounds) {
  particles = [];
  for (let i = 0; i < count; i++) {
    particles.push({
      x: p.random(bounds, CW - bounds),
      y: p.random(bounds, CW - bounds),
      vx: 0, vy: 0,
      colorIdx: i,
      weight: p.random(0.5, 3.0),
      trail: [],
      age: 0,
      maxAge: p.floor(p.random(200, 500))
    });
  }
}

function initWaves(count, pal) {
  waves = [];
  for (let i = 0; i < count; i++) {
    let isVert = p.random() < 0.5;
    waves.push({
      pos: (i / count) * CW,
      size: p.random(0.75, 1.25) * CW,
      thickness: p.random(0.05, 0.25) * CW,
      color: getColor(i, pal, 0),
      opacity: p.random(20, 50),
      speed: p.random(0.003, 0.015),
      amplitude: p.random(20, 60),
      isVertical: isVert,
      offset: p.random(TWO_PI)
    });
  }
}

function initBgParticles(pal) {
  bgParticles = [];
  for (let i = 0; i < 8; i++) {
    bgParticles.push({
      x: p.random(CW), y: p.random(CW),
      radius: p.random(15, 60),
      color: getColor(i, pal, 0),
      driftSpeed: p.random(0.002, 0.008),
      driftAmp: p.random(10, 30),
      offset: p.random(TWO_PI)
    });
  }
}

function initBreathing(pal) {
  breathCircles = [];
  for (let i = 0; i < 4; i++) {
    breathCircles.push({
      cx: p.random(CW * 0.2, CW * 0.8),
      cy: p.random(CW * 0.2, CW * 0.8),
      baseR: p.random(20, 60),
      color: getColor(i, pal, 0),
      speed: p.random(0.015, 0.04),
      offset: p.random(TWO_PI)
    });
  }
}

// ─── NOISE-BASED FLOW FIELD ───────────────────────────────────────
function flowAngle(x, y, ns, chaos) {
  let n1 = p.noise(x * ns + noiseOff, y * ns + noiseOff, time);
  let n2 = p.noise(x * ns * 1.3 + noiseOff + 100, y * ns * 0.8 + noiseOff + 100, time * 1.1);
  return (n1 + n2 * 0.5) * TWO_PI * chaos;
}

// ─── MIRROR POINT ─────────────────────────────────────────────────
function mirrorPoint(x, y, axisIdx, totalAxes) {
  let cx = CW / 2, cy = CW / 2;
  let angle = axisIdx * (TWO_PI / totalAxes);
  let cos = Math.cos(angle), sin = Math.sin(angle);
  let tx = x - cx, ty = y - cy;
  let rx = tx * cos + ty * sin;
  let ry = -tx * sin + ty * cos;
  return { x: cx + rx * cos - (-ry) * sin, y: cy + rx * sin + (-ry) * cos };
}

// ─── DRAW WAVES ───────────────────────────────────────────────────
function drawWaves(waveParams) {
  if (waveParams.count === 0) return;
  p.noStroke();
  for (let w of waves) {
    let drift = Math.sin(p.frameCount * w.speed + w.offset) * w.amplitude;
    p.push();
    let c = w.color;
    p.fill(p.hue(c), p.saturation(c), p.brightness(c), w.opacity);
    if (w.isVertical) {
      p.rect(w.pos + drift, 0, w.thickness, w.size);
    } else {
      p.rect(0, w.pos + drift, w.size, w.thickness);
    }
    p.pop();
  }
}

// ─── DRAW BG PARTICLES ────────────────────────────────────────────
function drawBgParticles() {
  p.noStroke();
  for (let bg of bgParticles) {
    let dx = Math.sin(p.frameCount * bg.driftSpeed + bg.offset) * bg.driftAmp;
    let dy = Math.cos(p.frameCount * bg.driftSpeed * 0.7 + bg.offset) * bg.driftAmp * 0.5;
    let c = bg.color;
    p.fill(p.hue(c), p.saturation(c), p.brightness(c), 25);
    p.circle(bg.x + dx, bg.y + dy, bg.radius * 2);
  }
}

// ─── DRAW BREATHING ───────────────────────────────────────────────
function drawBreathing() {
  p.noFill();
  for (let bc of breathCircles) {
    let pulse = Math.sin(p.frameCount * bc.speed + bc.offset);
    let r = bc.baseR * (1 + pulse * 0.3);
    let opac = 15 + pulse * 10;
    let c = bc.color;
    p.stroke(p.hue(c), p.saturation(c), p.brightness(c), opac);
    p.strokeWeight(1.5);
    p.circle(bc.cx, bc.cy, r * 2);
  }
  p.noStroke();
}

// ─── DRAW GRAIN ───────────────────────────────────────────────────
function drawGrain(opacity) {
  if (opacity <= 0) return;
  p.loadPixels();
  let d = p.pixelDensity();
  let total = 4 * (CW * d) * (CW * d);
  let strength = opacity * 80;
  for (let i = 0; i < total; i += 4) {
    let noise = (p.random() - 0.5) * strength;
    p.pixels[i]   += noise;
    p.pixels[i+1] += noise;
    p.pixels[i+2] += noise;
  }
  p.updatePixels();
}

// ─── DRAW FRAME ───────────────────────────────────────────────────
function drawFrame(style, pal) {
  if (style.width <= 0) return;
  let fw = style.width * CW;
  let mw = style.matting ? fw * 2.5 : 0;
  let totalBorder = fw + mw;
  p.push();
  p.colorMode(p.RGB, 255);

  // Matting
  if (style.matting) {
    p.noStroke();
    p.fill(255, 253, 245);
    // Top matting
    p.rect(fw, fw, CW - fw*2, mw);
    // Bottom matting
    p.rect(fw, CW - fw - mw, CW - fw*2, mw);
    // Left matting
    p.rect(fw, fw, mw, CW - fw*2);
    // Right matting
    p.rect(CW - fw - mw, fw, mw, CW - fw*2);

    // Paper texture dots on matting
    p.fill(210, 205, 195, 30);
    for (let i = 0; i < 30; i++) {
      let gx = p.random(fw, CW - fw);
      let gy = p.random(fw, CW - fw);
      if (gx < totalBorder || gx > CW - totalBorder || gy < totalBorder || gy > CW - totalBorder) {
        p.circle(gx, gy, p.random(1, 3));
      }
    }

    // Inner shadow line
    p.stroke(0, 0, 0, 20);
    p.strokeWeight(1.5);
    p.noFill();
    p.rect(totalBorder, totalBorder, CW - totalBorder*2, CW - totalBorder*2);
  }

  // Frame border
  let frameColor = pal.length > 0 ? pal[0] : '#2a2a2a';
  let fc = hexToRGB(frameColor);
  p.stroke(fc[0], fc[1], fc[2]);
  p.strokeWeight(fw);
  p.noFill();
  p.rect(fw/2, fw/2, CW - fw, CW - fw);

  p.pop();
  p.colorMode(p.HSB, 360, 100, 100, 100);
}

function hexToRGB(hex) {
  return [
    parseInt(hex.slice(1,3),16),
    parseInt(hex.slice(3,5),16),
    parseInt(hex.slice(5,7),16)
  ];
}

// ─── DRAW TRAIL ───────────────────────────────────────────────────
function drawTrail(pt, style, opac, pal, shift, distStr) {
  if (pt.trail.length < 2) return;
  let col = getColor(pt.colorIdx, pal, shift);
  let ageOpac = (1 - (pt.age / pt.maxAge) * 0.5) * opac * 100;
  p.stroke(p.hue(col), p.saturation(col), p.brightness(col), ageOpac);
  p.strokeWeight(pt.weight);
  p.noFill();

  let useCurve = style === 'smooth' || (style === 'mixed' && pt.colorIdx % 2 === 0);

  // Apply distortion offset
  let applyDist = distStr > 0;

  if (useCurve && pt.trail.length > 3) {
    p.beginShape();
    for (let i = 0; i < pt.trail.length; i++) {
      let tx = pt.trail[i].x;
      let ty = pt.trail[i].y;
      if (applyDist) {
        let ox = tx, oy = ty;
        tx += (p.noise(ox * 0.01, oy * 0.01, time * 0.3) - 0.5) * distStr;
        ty += (p.noise(ox * 0.01 + 500, oy * 0.01 + 500, time * 0.3) - 0.5) * distStr;
      }
      // Gradient along trail
      if (i > 0 && i % 5 === 0) {
        p.endShape();
        let t = i / pt.trail.length;
        let col2 = getColor(pt.colorIdx + 1, pal, shift);
        let lc = p.lerpColor(col, col2, t);
        p.stroke(p.hue(lc), p.saturation(lc), p.brightness(lc), ageOpac * (1 - t * 0.3));
        p.beginShape();
        p.curveVertex(tx, ty);
      }
      p.curveVertex(tx, ty);
    }
    p.endShape();
  } else {
    p.beginShape();
    for (let i = 0; i < pt.trail.length; i++) {
      let tx = pt.trail[i].x;
      let ty = pt.trail[i].y;
      if (applyDist) {
        let ox = tx, oy = ty;
        tx += (p.noise(ox * 0.01, oy * 0.01, time * 0.3) - 0.5) * distStr;
        ty += (p.noise(ox * 0.01 + 500, oy * 0.01 + 500, time * 0.3) - 0.5) * distStr;
      }
      p.vertex(tx, ty);
    }
    p.endShape();
  }
}

// ─── MAIN DRAW LOOP ───────────────────────────────────────────────
p.draw = function() {
  // Read all variables
  let vDensity    = p.getSynthVar('particle_density') || 'moderate';
  let vEnergy     = p.getSynthVar('flow_energy') || 'moderate';
  let vTrailLen   = p.getSynthVar('trail_length') || 'medium';
  let vTrailStyle = p.getSynthVar('trail_style') || 'smooth';
  let vTrailOpac  = p.getSynthVar('trail_opacity') || 'medium';
  let vNoise      = p.getSynthVar('noise_texture') || 'organic';
  let vPalette    = p.getSynthVar('color_palette') || 'warm sunset';
  let vShift      = p.getSynthVar('color_shift') || 'none';
  let vWave       = p.getSynthVar('wave_pattern') || 'subtle';
  let vGrain      = p.getSynthVar('grain_texture') || 'none';
  let vSymmetry   = p.getSynthVar('symmetry_mode') || 'none';
  let vFrame      = p.getSynthVar('frame_style') || 'none';
  let vDist       = p.getSynthVar('distortion') || 'none';

  // Map to numeric params
  let numParticles = densityMap[vDensity] || 80;
  let energy = energyMap[vEnergy] || energyMap.moderate;
  let maxTrail = trailLenMap[vTrailLen] || 20;
  let trailOpac = trailOpMap[vTrailOpac] || 0.4;
  let ns = noiseMap[vNoise] || 0.012;
  palette = PALETTES[vPalette] || PALETTES['warm sunset'];
  let shift = colorShiftMap[vShift] || 0;
  let waveParams = waveMap[vWave] || waveMap.subtle;
  let grainOpac = grainMap[vGrain] || 0;
  let symAxes = symMap[vSymmetry] || 0;
  let frameStyle = frameMap[vFrame] || frameMap.none;
  let distStr = distMap[vDist] || 0;

  let frameBounds = (frameStyle.width + (frameStyle.matting ? frameStyle.width * 2.5 : 0)) * CW;

  // Reinit on density change
  if (numParticles !== prevDensity) {
    prevDensity = numParticles;
    initParticles(numParticles, frameBounds + 5);
  }

  // Reinit palette-dependent elements
  if (vPalette !== prevPaletteName) {
    prevPaletteName = vPalette;
    initBgParticles(palette);
    initBreathing(palette);
    if (waveParams.count > 0) {
      initWaves(waveParams.count, palette);
      prevWaveCount = waveParams.count;
    }
    // Recolor particles
    for (let pt of particles) {
      pt.colorIdx = particles.indexOf(pt);
    }
  }

  // Reinit waves on count change
  if (waveParams.count !== prevWaveCount) {
    prevWaveCount = waveParams.count;
    initWaves(waveParams.count, palette);
  }

  // Background
  let bgCol = getColor(0, palette, 0);
  p.background(p.hue(bgCol), p.saturation(bgCol) * 0.15, 8, 100);

  // Fade trails with semi-transparent overlay
  p.noStroke();
  p.fill(p.hue(bgCol), p.saturation(bgCol) * 0.15, 8, 8);
  p.rect(0, 0, CW, CW);

  time += 0.008;

  // Layer 1: Waves
  drawWaves(waveParams);

  // Layer 2: Background particles
  drawBgParticles();

  // Layer 3: Breathing circles
  drawBreathing();

  // Layer 4: Update and draw flow field particles
  let bounds = frameBounds + 2;
  for (let pt of particles) {
    let angle = flowAngle(pt.x, pt.y, ns, energy.chaos);
    let force = energy.speed * 1.5;
    pt.vx += Math.cos(angle) * force;
    pt.vy += Math.sin(angle) * force;
    pt.vx *= 0.97;
    pt.vy *= 0.97;
    pt.trail.push({ x: pt.x, y: pt.y });
    if (pt.trail.length > maxTrail) pt.trail.shift();
    pt.x += pt.vx;
    pt.y += pt.vy;
    pt.age++;

    // Respawn
    if (pt.age > pt.maxAge || pt.x < bounds || pt.x > CW - bounds || pt.y < bounds || pt.y > CW - bounds) {
      pt.x = p.random(bounds, CW - bounds);
      pt.y = p.random(bounds, CW - bounds);
      pt.vx = 0; pt.vy = 0;
      pt.trail = [];
      pt.age = 0;
    }

    // Draw primary trail
    drawTrail(pt, vTrailStyle, trailOpac, palette, shift, distStr);

    // Draw symmetry mirrors
    if (symAxes > 0) {
      for (let ax = 1; ax < symAxes; ax++) {
        let mirroredTrail = pt.trail.map(tp => mirrorPoint(tp.x, tp.y, ax, symAxes));
        let mirrorPt = { trail: mirroredTrail, colorIdx: pt.colorIdx, weight: pt.weight, age: pt.age, maxAge: pt.maxAge };
        drawTrail(mirrorPt, vTrailStyle, trailOpac * 0.65, palette, shift, distStr);
      }
    }
  }

  // Layer 5: Grain overlay
  if (grainOpac > 0 && p.frameCount % 3 === 0) {
    drawGrain(grainOpac);
  }

  // Layer 6: Frame and matting (on top)
  drawFrame(frameStyle, palette);
};
